from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject (first triple's subject)
    main_subject = triples[0].subject

    # Build sentence parts with proper connectors
    parts = []
    for i, t in enumerate(triples):
        subj = t.subject
        pred = t.predicate
        obj = t.object

        if pred == "birthPlace":
            part = f"{subj} was born in {obj}"
        elif pred == "birthDate":
            part = f"{subj} was born on {obj}"
        elif pred == "birthYear":
            part = f"{subj} was born in {obj}"
        elif pred == "deathPlace":
            part = f"{subj} died in {obj}"
        elif pred == "deathDate":
            part = f"{subj} died on {obj}"
        elif pred == "deathYear":
            part = f"{subj} died in {obj}"
        elif pred == "nationality":
            part = f"{subj} is a {obj} national"
        elif pred == "party":
            part = f"{subj} belongs to the {obj} party"
        elif pred == "office":
            part = f"{subj} held the office of {obj}"
        elif pred == "successor":
            part = f"{subj} was succeeded by {obj}"
        elif pred == "predecessor":
            part = f"{subj} was preceded by {obj}"
        elif pred == "spouse":
            part = f"{subj} was married to {obj}"
        elif pred == "residence":
            part = f"{subj} resides at {obj}"
        elif pred == "region":
            part = f"{subj} is from the region of {obj}"
        elif pred == "country":
            part = f"{subj} is from {obj}"
        elif pred == "capital":
            part = f"{subj}'s capital is {obj}"
        elif pred == "largestCity":
            part = f"{subj}'s largest city is {obj}"
        elif pred == "currency":
            part = f"{obj} is the currency of {subj}"
        elif pred == "language":
            part = f"{obj} is spoken in {subj}"
        elif pred == "officialLanguage":
            part = f"{subj}'s official language is {obj}"
        elif pred == "leader":
            part = f"{obj} leads {subj}"
        elif pred == "battle":
            part = f"{subj} participated in the {obj}"
        elif pred == "almaMater":
            part = f"{subj} studied at {obj}"
        elif pred == "profession":
            part = f"{subj} worked as a {obj}"
        elif pred == "religion":
            part = f"{subj} follows {obj}"
        elif pred == "militaryBranch":
            part = f"{subj} served in the {obj}"
        elif pred == "militaryRank":
            part = f"{subj} held the rank of {obj}"
        elif pred == "state":
            part = f"{subj} is from {obj}"
        elif pred == "award":
            part = f"{subj} received the {obj}"
        elif pred == "activeYearsStartDate":
            part = f"{subj} started in {obj}"
        elif pred == "activeYearsEndDate":
            part = f"{subj} ended in {obj}"
        else:
            part = f"{subj} {pred} {obj}"

        parts.append(part)

    # Join parts into one complex sentence
    if len(parts) == 1:
        return parts[0] + "."
    else:
        # Use commas and 'and' for the last part
        if len(parts) == 2:
            return parts[0] + " and " + parts[1] + "."
        else:
            return ", ".join(parts[:-1]) + ", and " + parts[-1] + "."

